INSERT INTO `questions` (`id`, `content`, `subject`, `difficulty`, `options`, `correctAnswer`, `topic`, `avgTime`, `errorRate`) VALUES
('#Q-90001', 'Câu hỏi số 1: Nội dung kiến thức trọng tâm của môn học Cơ sở dữ liệu nâng cao. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Cơ sở dữ liệu nâng cao', 'Trung bình', '["Phương án trả lời A cho câu hỏi số 1","Phương án trả lời B cho câu hỏi số 1","Phương án trả lời C cho câu hỏi số 1","Phương án trả lời D cho câu hỏi số 1"]', 1, 'Chuyên đề 2', '02:22', 25.5),
('#Q-90002', 'Câu hỏi số 2: Nội dung kiến thức trọng tâm của môn học Trí tuệ nhân tạo & Học máy. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Trí tuệ nhân tạo & Học máy', 'Khó', '["Phương án trả lời A cho câu hỏi số 2","Phương án trả lời B cho câu hỏi số 2","Phương án trả lời C cho câu hỏi số 2","Phương án trả lời D cho câu hỏi số 2"]', 2, 'Chuyên đề 3', '03:34', 31.4),
('#Q-90003', 'Câu hỏi số 3: Nội dung kiến thức trọng tâm của môn học Mạng máy tính cơ bản. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Mạng máy tính cơ bản', 'Dễ', '["Phương án trả lời A cho câu hỏi số 3","Phương án trả lời B cho câu hỏi số 3","Phương án trả lời C cho câu hỏi số 3","Phương án trả lời D cho câu hỏi số 3"]', 3, 'Chuyên đề 4', '04:46', 40.8),
('#Q-90004', 'Câu hỏi số 4: Nội dung kiến thức trọng tâm của môn học Lập trình ứng dụng Web. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Lập trình ứng dụng Web', 'Trung bình', '["Phương án trả lời A cho câu hỏi số 4","Phương án trả lời B cho câu hỏi số 4","Phương án trả lời C cho câu hỏi số 4","Phương án trả lời D cho câu hỏi số 4"]', 0, 'Chuyên đề 5', '01:58', 47.2),
('#Q-90005', 'Câu hỏi 5: Tìm giới hạn Lim (x -> 0) của hàm số f(x) = (sin 3x) / x.', 'Giải tích I & II', 'Khó', '["3","1","0","Không tồn tại"]', 1, 'Giới hạn hàm số', '02:21', 53.4),
('#Q-90006', 'Câu hỏi số 6: Nội dung kiến thức trọng tâm của môn học Đại số tuyến tính. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Đại số tuyến tính', 'Dễ', '["Phương án trả lời A cho câu hỏi số 6","Phương án trả lời B cho câu hỏi số 6","Phương án trả lời C cho câu hỏi số 6","Phương án trả lời D cho câu hỏi số 6"]', 2, 'Chuyên đề 2', '03:33', 58.8),
('#Q-90007', 'Câu hỏi số 7: Nội dung kiến thức trọng tâm của môn học Xác suất thống kê ứng dụng. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Xác suất thống kê ứng dụng', 'Trung bình', '["Phương án trả lời A cho câu hỏi số 7","Phương án trả lời B cho câu hỏi số 7","Phương án trả lời C cho câu hỏi số 7","Phương án trả lời D cho câu hỏi số 7"]', 3, 'Chuyên đề 3', '04:45', 66.9),
('#Q-90008', 'Câu hỏi số 8: Nội dung kiến thức trọng tâm của môn học Toán học rời rạc. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Toán học rời rạc', 'Khó', '["Phương án trả lời A cho câu hỏi số 8","Phương án trả lời B cho câu hỏi số 8","Phương án trả lời C cho câu hỏi số 8","Phương án trả lời D cho câu hỏi số 8"]', 0, 'Chuyên đề 4', '01:57', 75.1),
('#Q-90009', 'Câu hỏi số 9: Nội dung kiến thức trọng tâm của môn học Vật lý đại cương. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Vật lý đại cương', 'Dễ', '["Phương án trả lời A cho câu hỏi số 9","Phương án trả lời B cho câu hỏi số 9","Phương án trả lời C cho câu hỏi số 9","Phương án trả lời D cho câu hỏi số 9"]', 1, 'Chuyên đề 5', '02:20', 78.5),
('#Q-90010', 'Câu hỏi số 10: Nội dung kiến thức trọng tâm của môn học Vật lý lượng tử cơ bản. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Vật lý lượng tử cơ bản', 'Trung bình', '["Phương án trả lời A cho câu hỏi số 10","Phương án trả lời B cho câu hỏi số 10","Phương án trả lời C cho câu hỏi số 10","Phương án trả lời D cho câu hỏi số 10"]', 2, 'Chuyên đề 1', '03:32', 23.1),
('#Q-90011', 'Câu hỏi số 11: Nội dung kiến thức trọng tâm của môn học Điện từ học ứng dụng. Phương án nào mô tả chính xác nhất nguyên lý vận hành của chủ đề này?', 'Điện từ học ứng dụng', 'Khó', '["Phương án trả lời A cho câu hỏi số 11","Phương án trả lời B cho câu hỏi số 11","Phương án trả lời C cho câu hỏi số 11","Phương án trả lời D cho câu hỏi số 11"]', 3, 'Chuyên đề 2', '04:44', 28.3),
