-- 1. Departments Table
DROP TABLE IF EXISTS `departments`;
CREATE TABLE `departments` (
  `id` VARCHAR(50) PRIMARY KEY,
  `name` VARCHAR(255) NOT NULL,
  `head` VARCHAR(255),
  `teacherCount` INT DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 2. Subjects Table
DROP TABLE IF EXISTS `subjects`;
CREATE TABLE `subjects` (
  `code` VARCHAR(50) PRIMARY KEY,
  `name` VARCHAR(255) NOT NULL,
  `credits` INT NOT NULL,
  `questionCount` INT DEFAULT 0,
  `deptId` VARCHAR(50),
  FOREIGN KEY (`deptId`) REFERENCES `departments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 3. Users Table
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `email` VARCHAR(150) UNIQUE NOT NULL,
  `password` VARCHAR(255) NOT NULL,
  `name` VARCHAR(255) NOT NULL,
  `role` VARCHAR(50) NOT NULL,
  `studentId` VARCHAR(50) DEFAULT NULL,
  `department` VARCHAR(100) DEFAULT 'Khoa CNTT',
  `status` VARCHAR(50) DEFAULT 'Active',
  `createdAt` VARCHAR(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 4. Questions Table
DROP TABLE IF EXISTS `questions`;
CREATE TABLE `questions` (
  `id` VARCHAR(50) PRIMARY KEY,
  `content` TEXT NOT NULL,
  `subject` VARCHAR(100),
  `difficulty` VARCHAR(50),
  `options` TEXT NOT NULL,
  `correctAnswer` INT NOT NULL,
  `topic` VARCHAR(100),
  `avgTime` VARCHAR(50),
  `errorRate` FLOAT DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 5. Active Exams Table
DROP TABLE IF EXISTS `active_exams`;
CREATE TABLE `active_exams` (
  `id` VARCHAR(50) PRIMARY KEY,
  `title` VARCHAR(255) NOT NULL,
  `subject` VARCHAR(100),
  `duration` INT DEFAULT 60,
  `questionCount` INT DEFAULT 10,
  `description` TEXT,
  `iconName` VARCHAR(100) DEFAULT 'assignment',
  `category` VARCHAR(100) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 6. Exam History Table
DROP TABLE IF EXISTS `exam_history`;
CREATE TABLE `exam_history` (
  `id` VARCHAR(50) PRIMARY KEY,
  `title` VARCHAR(255) NOT NULL,
  `department` VARCHAR(100) DEFAULT NULL,
  `userEmail` VARCHAR(150) NOT NULL,
  `submitDate` VARCHAR(50) DEFAULT NULL,
  `score` VARCHAR(50) DEFAULT NULL,
  `result` VARCHAR(50) DEFAULT NULL,
  `iconName` VARCHAR(100) DEFAULT 'assignment',
  `questionsDetail` TEXT NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 7. System Settings Table
DROP TABLE IF EXISTS `system_settings`;
CREATE TABLE `system_settings` (
  `setting_key` VARCHAR(100) PRIMARY KEY,
  `setting_value` VARCHAR(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- 8. System Logs Table
DROP TABLE IF EXISTS `system_logs`;
CREATE TABLE `system_logs` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `time` VARCHAR(50) NOT NULL,
  `level` VARCHAR(50) NOT NULL,
  `message` TEXT NOT NULL,
  `source` VARCHAR(100) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

